import React from 'react';
import {
    Container, Table, Modal,
    Button,
    // Pagination, Button, Modal, Row, Col, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';

import PropTypes from 'prop-types';
import "./report-styles.css";

import { DataContext } from '../data-context.js';
import moment from 'moment'; // https://momentjs.com/
const util = require('../util.js');

export default class JobSummaryReport extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        startDate: PropTypes.string,
        endDate: PropTypes.string,
    };

    data = {};
    vendors = [];
    vendorMap = {};

    users = [];
    userMap = {};
    limit = 0;

    constructor(...args) {
        super(...args);

        this.state = {
            startDate: this.props.startDate,
            endDate: this.props.endDate,
            loading: false,
        }

        console.log(this.state)
    }

    handleKeyDown = (event) => {
        switch (event.keyCode) {
            case 27:
                this.props.onClose()
                break;
            default:
                break;
        }

    }


    // UNSAFE_componentWillReceiveProps() {
    UNSAFE_componentWillMount() {
        console.log('UNSAFE_componentWillReceiveProps fetchJobsByRange', this.state.startDate, this.state.endDate)
        // this.fetchjobs();

        document.addEventListener("keydown", this.handleKeyDown);
        this.setState(
            { loading: true },
            () => util.fetchJobsByRange(this.state.startDate, this.state.endDate)
                .then(res => this.setState({
                    jobs: res.data,
                    loading: false
                }))
        )
    }

    // fetchjobs() {
    //     util.fetchjobs(this.state.part._id,
    //         (res) => {
    //             console.log('fetchTransaction', res);
    //             this.setState({
    //                 jobs: res.data
    //             });
    //         },
    //         (err) => {
    //             console.error(err);
    //         }, this.limit);
    // }




    render() {
        // let part = this.props.part;
        // let users = this.state.users;
        // console.log('part', part)

        /* show={this.state.showDatePickerForm} */
        console.log('jobs', this.state.jobs);
        if (this.state.loading) {
            return (
                <Container fluid style={{ backgroundColor: '#ffffff' }}>
                    <h1>Loading...</h1>
                </Container>
            )
        }
        if (!this.state.jobs || this.state.jobs.length === 0) {
            return (
                <Modal
                    show={true}
                    onHide={this.props.onClose}
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    keyboard>
                    <Modal.Header closeButton>
                        <Modal.Title>Job Report</Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <h2>No Data on {this.props.startDate}</h2>
                    </Modal.Body>
                    <Modal.Footer>
                        <Button onClick={this.props.onClose}>Close</Button>
                    </Modal.Footer>
                </Modal>
            )
        }

        let totalRepairJobs = this.state.jobs.length
        let totalSetupJobs = 0
        let totalBreakdownJobs = 0
        let totalOtherJobs = 0
        let totalRepairTime = 0
        let totalSetupTime = 0
        let totalBreakdownTime = 0
        let totalOtherTime = 0
        let successCount = 0
        let totalRunMachineTime = 0 // ???
        let totalRepairMan = 0
        let averageRepairTime = 0
        let totalWaitForRepairTime = 0 // ???
        let repairManMap = new Set()


        let jobs = this.state.jobs.map((v, i) => {


            let rqTime = moment(v.request_time)
            let rpTime = moment(v.repair_time)
            let fTime = moment(v.finish_time)

            let ms, d;

            ms = fTime.diff(rpTime);
            totalRepairTime += ms;
            // d = moment.duration(ms);
            // totalRepairTime += d;
            let repairTime = util.getDurationTimeText(ms)
            // let repairTime = Math.floor(d.asHours()) + moment.utc(ms).format(":mm:ss");
            // totalRepairTime += d.as('ms');

            ms = fTime.diff(rqTime);
            let downTime = util.getDurationTimeText(ms)
            // d = moment.duration(ms);
            // let downTime = Math.floor(d.asHours()) + moment.utc(ms).format(":mm:ss");

            // Other calculations
            if (v.finish_work_type === 'SETUP') {
                totalSetupJobs++;
                // totalSetupTime += d.as('milliseconds'); // 50291000
                totalSetupTime += ms;

            } else if (v.finish_work_type == 'BREAK DOWN') {
                totalBreakdownJobs++;
                // totalBreakdownTime += d.as('milliseconds');
                totalBreakdownTime += ms
            } else if (v.finish_work_type == 'OTHER') {
                totalOtherJobs++;
                // totalOtherTime += d.as('milliseconds');
                totalOtherTime += ms
            }

            if (v.repair_user_code !== '')
                repairManMap.add(v.repair_user_code)



            return (
                <tr key={i + 1}>
                    <td>{i + 1}</td>
                    <td>{v.machine_code}</td>
                    <td>{v.machine_name}</td>
                    <td>{v.line_name}</td>
                    <td>{v.request_user_name}</td>
                    <td>{util.getDateText(v.request_time)}</td>
                    <td className="l">{v.request_cause}</td>
                    <td>{v.repair_user_name}</td>
                    <td>{util.getDateText(v.repair_time)}</td>
                    <td>{util.getDateText(v.finish_time)}</td>
                    <td>{repairTime}</td>
                    <td>{downTime}</td>
                    <td>{v.finish_work_type}</td>
                    <td>{v.finish_cause}</td>
                    <td>{v.code}</td>
                </tr>
            )
        });


        totalRepairMan = repairManMap.size

        let d = moment.duration(Math.floor(totalRepairTime / totalRepairJobs));
        averageRepairTime = this.getDurationTimeText(Math.floor(totalRepairTime / totalRepairJobs))
        console.log(totalRepairTime, totalRepairJobs, Math.floor(totalRepairTime / totalRepairJobs))

        // averageRepairTime = moment(totalRepairTime/totalRepairJobs).format('HH:mm:ss')

        return (
            <Container fluid style={{ backgroundColor: '#ffffff' }}>
                <Table id="table-history" bordered hover size="xl">
                    <tbody>
                        <tr>
                            <td><b>Honda Lock</b></td>
                            <td><b>Honda Lock Thai Co.,Ltd.</b></td>
                            <td className="r">ฝ่ายควบคุม : MANUFACTURING  ENGINEERING</td>
                        </tr>
                    </tbody>
                </Table>
                <Table id="table-history" bordered hover size="sm">
                    <tbody>
                        <tr>
                            <th>Total Repair List</th><td>{totalRepairJobs}</td>
                            <th>Setup</th><td>{totalSetupJobs}</td>
                            <th>Breakdown</th><td>{totalBreakdownJobs}</td>
                            <th>Other</th><td>{totalOtherJobs}</td>
                        </tr>
                        <tr>
                            <th>Total Repair Time</th><td>{this.getDurationTimeText(totalRepairTime)}</td>
                            <th>Setup Time</th><td>{this.getDurationTimeText(totalSetupTime)}</td>
                            <th>Breakdown Time</th><td>{this.getDurationTimeText(totalBreakdownTime)}</td>
                            <th>Other Time</th><td>{this.getDurationTimeText(totalOtherTime)}</td>
                        </tr>
                        <tr>
                            <th>All Run Machine Times</th><td>{totalRunMachineTime}</td>
                            <th>Total Repair</th><td>{totalRepairMan} men</td>
                            <th>Average for Repair Times</th><td>{averageRepairTime}</td>
                            <th>Wait For Repair</th><td>{this.getDurationTimeText(totalWaitForRepairTime)}</td>
                        </tr>
                    </tbody>
                </Table>
                {/* <span>
                    totalRepairList: {totalRepairJobs}<br />
                    totalSetupJobs: {totalSetupJobs}<br />
                    totalBreakdownJobs: {totalBreakdownJobs}<br />
                    totalOtherJobs: {totalOtherJobs}<br />
                    totalRepairTime: {moment(totalRepairTime).format('HH:mm:ss')} {totalRepairTime}<br />
                    totalSetupTime: {moment(totalSetupTime).format('HH:mm:ss')}<br />
                    totalBreakdownTime: {moment(totalBreakdownTime).format('HH:mm:ss')}<br />
                    totalOtherTime: {moment(totalOtherTime).format('HH:mm:ss')}<br />
                    let successCount<br />
                    let totalRunMachineTime<br />
                    totalRepairMan:{totalRepairMan}<br />
                    averageRepairTime:{averageRepairTime} {d.as('ms')}<br />
                </span> */}
                <Table id="table-history" striped bordered hover size="sm">
                    <thead>
                        <tr>
                            <th>No</th>
                            <th>Machine Code</th>
                            <th>Machine Name</th>
                            <th>Line</th>
                            <th>Request Name</th>
                            <th>Request Time</th>
                            <th>Cause</th>
                            <th>Repair Name</th>
                            <th>Repair Time</th>
                            <th>Finish Time</th>
                            <th>Total Repair Time</th>
                            <th>Total Time Break Down</th>
                            <th>Breakdown / Setup</th>
                            <th>Caused From</th>
                            <th>Change Profile Form No.</th>

                        </tr>
                    </thead>
                    <tbody>
                        {jobs}
                    </tbody>
                </Table>
            </Container>
        )
    }
}

